// famililook-shared/src/locale/useCurrency.js
// Currency detection and formatting hook.
// Priority: AppStorage override > navigator.language > USD fallback.
// Uses Intl.NumberFormat — never manual string concatenation.

import { useState, useCallback, useMemo } from 'react'
import { CURRENCIES, LOCALE_CURRENCY_MAP, DEFAULT_CURRENCY, SUPPORTED_CODES } from './currencyConfig.js'

const STORAGE_KEY = 'fl:currency'

/**
 * Detect currency from AppStorage or browser locale.
 * @returns {string} Currency code (GBP, USD, EUR, CAD)
 */
function detectCurrency() {
  // Priority 1: AppStorage explicit override
  try {
    if (typeof localStorage !== 'undefined') {
      const stored = localStorage.getItem(STORAGE_KEY)
      if (stored && CURRENCIES[stored]) return stored
    }
  } catch {
    // localStorage unavailable — continue to browser detection
  }

  // Priority 2: navigator.language country code
  if (typeof navigator !== 'undefined' && navigator.language) {
    const locale = navigator.language
    if (LOCALE_CURRENCY_MAP[locale]) return LOCALE_CURRENCY_MAP[locale]

    // Try language-only match (e.g. 'de' → check 'de-DE')
    const lang = locale.split('-')[0]
    for (const [key, code] of Object.entries(LOCALE_CURRENCY_MAP)) {
      if (key.startsWith(lang + '-')) return code
    }
  }

  // Priority 3: USD global default
  return DEFAULT_CURRENCY
}

/**
 * Currency hook for all Famili products.
 *
 * @returns {{
 *   currency: {code: string, symbol: string, locale: string, decimalPlaces: number},
 *   format: (amount: number) => string,
 *   setCurrency: (code: string) => void,
 *   source: 'override'|'browser'|'fallback',
 * }}
 */
export function useCurrency() {
  const [currencyCode, setCurrencyCode] = useState(detectCurrency)

  const currency = CURRENCIES[currencyCode] || CURRENCIES[DEFAULT_CURRENCY]

  const source = useMemo(() => {
    try {
      if (typeof localStorage !== 'undefined') {
        const stored = localStorage.getItem(STORAGE_KEY)
        if (stored && CURRENCIES[stored]) return 'override'
      }
    } catch { /* noop */ }

    if (typeof navigator !== 'undefined' && navigator.language) {
      const locale = navigator.language
      if (LOCALE_CURRENCY_MAP[locale]) return 'browser'
      const lang = locale.split('-')[0]
      for (const key of Object.keys(LOCALE_CURRENCY_MAP)) {
        if (key.startsWith(lang + '-')) return 'browser'
      }
    }

    return 'fallback'
  }, [currencyCode])

  const format = useCallback((amount) => {
    try {
      return new Intl.NumberFormat(currency.locale, {
        style: 'currency',
        currency: currency.code,
        minimumFractionDigits: currency.decimalPlaces,
        maximumFractionDigits: currency.decimalPlaces,
      }).format(amount)
    } catch {
      // Intl.NumberFormat not available — manual fallback
      return `${currency.symbol}${amount.toFixed(currency.decimalPlaces)}`
    }
  }, [currency])

  const setCurrency = useCallback((code) => {
    if (!SUPPORTED_CODES.includes(code)) return
    try {
      if (typeof localStorage !== 'undefined') {
        localStorage.setItem(STORAGE_KEY, code)
      }
    } catch { /* quota or access error — still update state */ }
    setCurrencyCode(code)
  }, [])

  return { currency, format, setCurrency, source }
}
